response_agent = Agent(
    name="ResponseGenerator",
    instructions="""Generate helpful, accurate responses using provided context.
    Maintain conversation coherence. Never hallucinate information.
    Structure: {'response': str, 'confidence': float}""",
    model="gpt-4o",
    tools=[]
)

@vex.guardrail(
    verifications=[
        "conversation_coherence",
        "response_accuracy",
        "hallucination_detection"
    ]
)
def generate_response(context: list, history: list, query: str) -> dict:
    full_context = f"History: {history}\nContext: {context}\nQuery: {query}"

    result = runner.run_sync(
        response_agent,
        full_context,
        thread_id="chat_1"
    )
    return {
        'response': result.final_output['response'],
        'confidence': result.final_output['confidence']
    }

safety_agent = Agent(
    name="SafetyAgent",
    instructions="Validate response: check PII, toxicity, coherence. Approve or reject.",
    model="gpt-4o",
    tools=[]
)

@vex.guardrail(
    verifications=[
        "safety_filtering",
        "pii_protection"
    ]
)
def validate_final_response(response: dict) -> dict:
    validation_prompt = f"""
    Response: {response['response']}
    History: {get_thread_history('chat_1')}

    Return: {{'approved': bool, 'reason': str, 'redacted_response': str}}
    """

    result = runner.run_sync(
        safety_agent,
        validation_prompt,
        thread_id="chat_1"
    )
    return result.final_output

