from vex.guardrails import LoopDetectionGuardrail

loop_guardrail = LoopDetectionGuardrail(
    max_handoffs=5,
    state_patterns=["intent_retrieval", "retrieval_response"],
    thread_id="chat_1"
)

@loop_guardrail
@vex.guardrail("response_accuracy")
def safe_agent_handoff(agent, message):
    return runner.run_sync(agent, message, thread_id="chat_1")

# Usage
intent_result = safe_agent_handoff(intent_agent, user_message)
if loop_guardrail.blocked:
    return "Conversation stuck in loop. Please rephrase."

from vex.guardrails import PiiProtectionGuardrail

pii_guardrail = PiiProtectionGuardrail(
    patterns=[
        r'\b\d{3}-\d{2}-\d{4}\b',  # SSN
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'  # Email
    ],
    replacement="[REDACTED]"
)

@pii_guardrail
@vex.guardrail("safety_filtering")
def protect_response(response_text: str) -> str:
    return response_text

# Integrates automatically with all @vex.guardrail decorators
